import json
out = {}
for k,v in globals().items():
    if k.startswith('var_call_'):
        if isinstance(v, list):
            # try to get first element
            try:
                first = v[0]
            except Exception:
                first = None
            out[k] = {'type': 'list', 'first': first}
        elif isinstance(v, str):
            out[k] = {'type': 'str', 'value_preview': v[:200]}
        else:
            out[k] = {'type': type(v).__name__, 'repr': str(v)[:200]}
print("__RESULT__:")
print(json.dumps(out))

